#include "neonate.h"
long long gpst(pid_t p){char path[256];snprintf(path,sizeof(path),"/proc/%d/stat",p);FILE*f=fopen(path,"r");if(!f)return -1;char buf[1024];long long st=-1;if(fgets(buf,sizeof(buf),f)){char*t=strtok(buf," ");for(int i=1;i<22&&t;i++)t=strtok(NULL," ");if(t)st=atoll(t);}fclose(f);return st;}
pid_t gmrp(){DIR*d=opendir("/proc");if(!d)return -1;struct dirent*e;pid_t rp=-1;long long rt=-1;while((e=readdir(d))!=NULL){int ip=1;for(int i=0;e->d_name[i];i++){if(!isdigit(e->d_name[i])){ip=0;break;}}if(ip){pid_t p=atoi(e->d_name);long long st=gpst(p);if(st>rt){rt=st;rp=p;}}}closedir(d);return rp;}
int ixkp(){struct termios ot,nt;int ch;tcgetattr(STDIN_FILENO,&ot);nt=ot;nt.c_lflag&=~(ICANON|ECHO);tcsetattr(STDIN_FILENO,TCSANOW,&nt);fd_set rf;struct timeval tv;FD_ZERO(&rf);FD_SET(STDIN_FILENO,&rf);tv.tv_sec=0;tv.tv_usec=100000;int r=select(STDIN_FILENO+1,&rf,NULL,NULL,&tv);if(r>0&&FD_ISSET(STDIN_FILENO,&rf)){ch=getchar();tcsetattr(STDIN_FILENO,TCSANOW,&ot);if(ch=='x'||ch=='X')return 1;}tcsetattr(STDIN_FILENO,TCSANOW,&ot);return 0;}
void pnc(const char*c){if(strstr(c,"-n")==NULL){fprintf(stderr,"Error: no -n flag\n");return;}int t;sscanf(c,"neonate -n %d",&t);while(1){pid_t p=gmrp();if(p==-1){fprintf(stderr,"Error\n");return;}printf("%d\n",p);fflush(stdout);sleep(t);if(ixkp())break;}}
